const outputItems = [];

const FILLER_REGEX = /^(so|yeah|hey|hi|hello|alright|listen|guys)\b/i;

const HOOK_SIGNAL_REGEX = /(stop|don't|do not|never|why|here's|this is|if you|you are|most people)/i;

for (const item of items) {
	const data = item.json;

	let transcript = data.transcript || "";
	transcript = transcript.trim();

	// Word count
	const wordCount = transcript ? transcript.split(/\s+/).length : 0;

	// Starts with filler
	const startsWithFiller = FILLER_REGEX.test(transcript);

	// Has hook signal language
	const hasHookSignal = HOOK_SIGNAL_REGEX.test(transcript);

	// Quality classification
	let transcriptQuality;

	if (wordCount === 0) {
		transcriptQuality = "empty";
	} else if (wordCount >= 6 && !startsWithFiller && hasHookSignal) {
		transcriptQuality = "strong";
	} else {
		transcriptQuality = "weak";
	}

	// Attach scoring fields
	data.transcript_word_count = wordCount;
	data.starts_with_filler = startsWithFiller;
	data.has_hook_signal = hasHookSignal;
	data.transcript_quality = transcriptQuality;

	outputItems.push({ json: data });
}

return outputItems;

const seen = new Set();

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

return items
  .map(item => {
    const transcript = String(item.json.transcript || '');

    const creatorId = String(item.json.creator_id);
    const sourceReelId = String(item.json.id);

    // composite unique key
    const uniqueKey = `${creatorId}::${sourceReelId}`;

    // skip duplicate
    if (seen.has(uniqueKey)) {
      return null;
    }

    seen.add(uniqueKey);

    return {
      json: {
        transcript_id: uuidv4(), // ✅ GENERATED HERE
        source_reel_id: sourceReelId,
        creator_id: creatorId,
        platform: item.json.platform || 'instagram',

        transcript_text: transcript,

        quality_score: item.json.transcript_quality
      }
    };
  })
  .filter(Boolean);

const outputItems = [];

// 1️⃣ Get raw Gemini output
let raw = $input.first().json.content.parts[0].text;

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

// 2️⃣ Remove markdown fences
raw = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

if (!raw) {
  throw new Error('Gemini returned empty text');
}

// 3️⃣ Parse JSON safely
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error(`Invalid JSON from Gemini:\n${raw}`);
}

// 4️⃣ Validate structure
if (!Array.isArray(parsed.hook_patterns)) {
  throw new Error('Expected "hook_patterns" array in Gemini output');
}

// 5️⃣ Emit ONE item per hook pattern
for (const pattern of parsed.hook_patterns) {
  outputItems.push({
    json: {
      pattern_name: pattern.pattern_name,
      template: pattern.template,
      hooks:pattern.hooks
    }
  });
}

return outputItems;

const outputItems = [];

for (const item of items) {
  const patternId = item.json.hook_pattern_id;
  const hooks = item.json.hooks;

  for (const hook of hooks) {
    outputItems.push({
      json: {
        hook_pattern_id: patternId,
        hook_text: hook
      }
    });
  }
}

return outputItems;

const creatorsMap = {};

for (const item of items) {
  const username = item.json.ownerUsername;
  const platform = item.json.platform ?? 'instagram';

  if (!username) {
    throw new Error(`Missing ownerUsername in item: ${JSON.stringify(item.json)}`);
  }

  const key = `${username}__${platform}`;

  if (!creatorsMap[key]) {
    creatorsMap[key] = {
      json: {
        creator_username: username,
        platform
      }
    };
  }
}

return Object.values(creatorsMap);

// Get transcript from current item
const transcript = ($json.transcript_text || "").trim();
const transcript_id  = $json.transcript_id

if (!transcript) {
  return {
    hook: ""
  };
}

// Split transcript into sentences
const sentences = transcript
  .split(/(?<=[.!?])\s+/)
  .map(s => s.trim())
  .filter(Boolean);

// Take first 1–2 sentences as hook
const hook = sentences.slice(0, 1).join(" ");

return {
  hook, transcript_id
};

return items.map(item => {
  const caption = String(item.json.caption || '');

  return {
    json: {
      source_reel_id: String(item.json.id),
      creator_id: item.json.creator_id,
      platform: item.json.platform || 'instagram',
      reel_url: item.json.url || null,
      caption:caption,
      views: Number(item.json.videoPlayCount ?? 0),
      likes: Number(item.json.likesCount ?? 0),
    }
  };
});

const outputItems = [];

for (const item of items) {
  const transcriptId = item.json.transcript_id;

  let raw = item.json?.content?.parts?.[0]?.text ?? '';
  raw = raw.replace(/```json|```/g, '').trim();

  const parsed = JSON.parse(raw);

  for (const idea of parsed.ideas) {
    outputItems.push({
      json: {
        transcript_id: transcriptId,
        idea_text: idea,
        status: 'generated'
      }
    });
  }
}

return outputItems;
